using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr root = design->rootComponent();
    if (!root)
        return false;

    // Have the edge selected and add it to an ObjectCollection.
    Ptr selection = ui->selectEntity("Select edge to fillet", "Edges");
    if (!selection)
        return false;

    Ptr edge = selection->entity();
    if (!edge)
        return false;

    Ptr edgeCollection = ObjectCollection::create();
    if (!edgeCollection)
        return false;
    edgeCollection->add(edge);

    Ptr feats = root->features();
    if (!feats)
        return false;

    Ptr fillets = feats->filletFeatures();
    if (!fillets)
        return false;

    Ptr filletInput = fillets->createInput();
    if (!filletInput)
        return false;
    filletInput->addConstantRadiusEdgeSet(edgeCollection, ValueInput::createByString(".25 in"), true);

    Ptr fillet = fillets->add(filletInput);
    return true;
}
